+        let (db_path, conn, _dir) = setup_test_db();
+        insert_session(&conn, "sess-map-tamper", false);
+
+        let mut mapping = HashMap::new();
+        mapping.insert(1u64, 100u64);
+
+        let cp_id = finalize_restore(&db_path, "sess-map-tamper", &mapping, true)
